{
  "name": "Suno AI Architect",
  "description": "An expert AI assistant that generates optimized style prompts and lyrics blueprints specifically designed for Suno AI music generation."
}

export interface SunoBlueprintResponse {
  suno_style: string;
  suno_lyrics: string;
  analysis: string;
}

export interface UserInput {
  genre: string;
  mood: string;
  vocals: string;
  language: string;
  tempo: string;
  additionalDetails: string;
}

export enum LoadingState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { UserInput, SunoBlueprintResponse } from "../types";

const SYSTEM_INSTRUCTION = `
## ROLE
Anda adalah "Suno AI Master Architect", asisten ahli dalam merancang blueprint musik (Style & Lyrics) untuk Suno AI. Tugas Anda adalah mengubah parameter teknis dan referensi audio menjadi instruksi yang bisa dipahami secara sempurna oleh model Suno.

## WORKFLOW LOGIC
1. Analisis Input: Evaluasi Genre, Vocal, Quality, dan Advanced Sculpting (FX/Humanize).
2. Generate Style: Gabungkan genre, mood, dan production quality ke dalam maksimal 120 karakter (limit Suno).
3. Generate Lyrics: Buat lirik dengan struktur lagu yang jelas menggunakan tag [Bracket] yang tepat.

## STYLE OPTIMIZATION RULES
- Gunakan deskripsi tekstur suara (misal: "Warm Analog", "Crispy Highs").
- Gunakan instrumen spesifik (misal: "Suling Javanese flute", "Heavy Reverb Synth").
- Hindari kata-kata deskriptif yang tidak berguna (misal: "Amazing", "Best").
- Pastikan Bahasa yang dipilih tercermin dalam diksi lirik.
- STRICT LIMIT: The 'suno_style' must be under 120 characters.

## LYRICS STRUCTURE RULES
Gunakan struktur standar:
- [Intro]
- [Verse 1]
- [Chorus]
- [Drop] (Jika EDM) or [Instrumental Interlude]
- [Bridge]
- [Outro]
- Masukkan Humanize tags seperti [breath], [chuckle], [whisper], or [clears throat] di tempat yang dramatis.

## FORMAT OUTPUT
You must return a JSON object.
`;

export const generateBlueprint = async (input: UserInput): Promise<SunoBlueprintResponse> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Create a Suno AI blueprint for the following song concept:
    - Genre/Style: ${input.genre}
    - Mood/Vibe: ${input.mood}
    - Vocals: ${input.vocals}
    - Language: ${input.language}
    - Tempo: ${input.tempo}
    - Additional Details: ${input.additionalDetails}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', // Good speed/quality balance for structured text
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suno_style: {
              type: Type.STRING,
              description: "The optimized style prompt for Suno (max 120 chars).",
            },
            suno_lyrics: {
              type: Type.STRING,
              description: "The complete lyrics with bracketed structural tags.",
            },
            analysis: {
              type: Type.STRING,
              description: "Brief explanation of why this combination was chosen.",
            },
          },
          required: ["suno_style", "suno_lyrics", "analysis"],
        },
      },
    });

    if (response.text) {
      return JSON.parse(response.text) as SunoBlueprintResponse;
    }
    throw new Error("No response generated");
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

