import React, { useState } from 'react';
import { UserInput, LoadingState } from '../types';
import { VOCAL_TYPES, TEMPO_OPTIONS, GENRE_EXAMPLES } from '../constants';
import { Sparkles, Loader2 } from 'lucide-react';

interface BlueprintFormProps {
  onSubmit: (data: UserInput) => void;
  loadingState: LoadingState;
}

const BlueprintForm: React.FC<BlueprintFormProps> = ({ onSubmit, loadingState }) => {
  const [formData, setFormData] = useState<UserInput>({
    genre: '',
    mood: '',
    vocals: 'Male Vocal',
    language: 'English',
    tempo: 'Mid-Tempo (90-110 BPM)',
    additionalDetails: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  const isLoading = loadingState === LoadingState.LOADING;

  return (
    <div className="w-full max-w-2xl mx-auto p-6 bg-suno-card border border-white/10 rounded-2xl shadow-xl">
      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Genre & Mood Row */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-2">
            <label className="text-xs font-mono uppercase tracking-wider text-white/50">Genre / Style</label>
            <input
              type="text"
              name="genre"
              list="genre-suggestions"
              value={formData.genre}
              onChange={handleChange}
              placeholder="e.g. Synthwave"
              className="w-full bg-black/20 border border-white/10 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-suno-primary focus:ring-1 focus:ring-suno-primary transition-all"
              required
            />
            <datalist id="genre-suggestions">
              {GENRE_EXAMPLES.map(g => <option key={g} value={g} />)}
            </datalist>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-mono uppercase tracking-wider text-white/50">Mood / Vibe</label>
            <input
              type="text"
              name="mood"
              value={formData.mood}
              onChange={handleChange}
              placeholder="e.g. Melancholic, High Energy"
              className="w-full bg-black/20 border border-white/10 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-suno-secondary focus:ring-1 focus:ring-suno-secondary transition-all"
              required
            />
          </div>
        </div>

        {/* Vocals, Language, Tempo Row */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="space-y-2">
            <label className="text-xs font-mono uppercase tracking-wider text-white/50">Vocals</label>
            <select
              name="vocals"
              value={formData.vocals}
              onChange={handleChange}
              className="w-full bg-black/20 border border-white/10 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-suno-primary appearance-none cursor-pointer"
            >
              {VOCAL_TYPES.map(v => <option key={v} value={v}>{v}</option>)}
            </select>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-mono uppercase tracking-wider text-white/50">Tempo</label>
            <select
              name="tempo"
              value={formData.tempo}
              onChange={handleChange}
              className="w-full bg-black/20 border border-white/10 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-suno-primary appearance-none cursor-pointer"
            >
              {TEMPO_OPTIONS.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-mono uppercase tracking-wider text-white/50">Language</label>
            <input
              type="text"
              name="language"
              value={formData.language}
              onChange={handleChange}
              className="w-full bg-black/20 border border-white/10 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-suno-primary"
            />
          </div>
        </div>

        {/* Additional Details */}
        <div className="space-y-2">
          <label className="text-xs font-mono uppercase tracking-wider text-white/50">Story / Theme / Specific Instruments</label>
          <textarea
            name="additionalDetails"
            value={formData.additionalDetails}
            onChange={handleChange}
            rows={3}
            placeholder="A song about a robot falling in love with a toaster. Use heavy bass and glitch effects."
            className="w-full bg-black/20 border border-white/10 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-suno-primary resize-none"
          />
        </div>

        {/* Submit Button */}
        <button
          type="submit"
          disabled={isLoading}
          className="w-full group relative overflow-hidden rounded-xl bg-gradient-to-r from-suno-primary to-suno-secondary p-[1px] focus:outline-none focus:ring-2 focus:ring-white focus:ring-offset-2 focus:ring-offset-black disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <div className="relative flex items-center justify-center gap-2 bg-black/80 hover:bg-black/40 transition-colors rounded-xl px-6 py-4 h-full w-full">
            {isLoading ? (
              <>
                <Loader2 className="w-5 h-5 animate-spin text-white" />
                <span className="font-semibold text-white tracking-wide">Architecting...</span>
              </>
            ) : (
              <>
                <Sparkles className="w-5 h-5 text-yellow-300" />
                <span className="font-semibold text-white tracking-wide">Generate Blueprint</span>
              </>
            )}
          </div>
        </button>
      </form>
    </div>
  );
};

export default BlueprintForm;

import React, { useState } from 'react';
import { SunoBlueprintResponse } from '../types';
import { Copy, Check, Music, FileText, Info } from 'lucide-react';

interface ResultDisplayProps {
  data: SunoBlueprintResponse;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ data }) => {
  const [copiedStyle, setCopiedStyle] = useState(false);
  const [copiedLyrics, setCopiedLyrics] = useState(false);

  const copyToClipboard = async (text: string, isStyle: boolean) => {
    try {
      await navigator.clipboard.writeText(text);
      if (isStyle) {
        setCopiedStyle(true);
        setTimeout(() => setCopiedStyle(false), 2000);
      } else {
        setCopiedLyrics(true);
        setTimeout(() => setCopiedLyrics(false), 2000);
      }
    } catch (err) {
      console.error('Failed to copy:', err);
    }
  };

  return (
    <div className="w-full max-w-4xl mx-auto space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">

      {/* Style Section */}
      <div className="bg-suno-card border border-white/10 rounded-xl overflow-hidden shadow-lg">
        <div className="bg-white/5 px-6 py-3 border-b border-white/10 flex items-center justify-between">
          <div className="flex items-center gap-2 text-suno-secondary">
            <Music className="w-4 h-4" />
            <h3 className="font-mono text-sm font-bold uppercase tracking-widest">Suno Style Prompt</h3>
          </div>
          <span className={`text-xs font-mono ${data.suno_style.length > 120 ? 'text-red-400' : 'text-green-400'}`}>
            {data.suno_style.length}/120 chars
          </span>
        </div>
        <div className="p-6 relative group">
          <p className="font-medium text-lg text-white font-mono break-words pr-12">
            {data.suno_style}
          </p>
          <button
            onClick={() => copyToClipboard(data.suno_style, true)}
            className="absolute top-1/2 -translate-y-1/2 right-4 p-2 bg-white/10 hover:bg-suno-secondary text-white rounded-lg transition-colors"
            title="Copy Style"
          >
            {copiedStyle ? <Check className="w-5 h-5" /> : <Copy className="w-5 h-5" />}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {/* Lyrics Section */}
        <div className="md:col-span-2 bg-suno-card border border-white/10 rounded-xl overflow-hidden shadow-lg flex flex-col">
          <div className="bg-white/5 px-6 py-3 border-b border-white/10 flex items-center justify-between">
            <div className="flex items-center gap-2 text-suno-primary">
              <FileText className="w-4 h-4" />
              <h3 className="font-mono text-sm font-bold uppercase tracking-widest">Lyrics & Structure</h3>
            </div>
            <button
              onClick={() => copyToClipboard(data.suno_lyrics, false)}
              className="flex items-center gap-2 text-xs font-mono uppercase bg-white/5 hover:bg-white/10 px-3 py-1.5 rounded transition-colors text-white"
            >
              {copiedLyrics ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />}
              {copiedLyrics ? 'Copied' : 'Copy All'}
            </button>
          </div>
          <div className="p-6 bg-[#0c0c0e] flex-grow">
            <pre className="font-mono text-sm leading-relaxed text-white/80 whitespace-pre-wrap max-h-[500px] overflow-y-auto">
              {data.suno_lyrics}
            </pre>
          </div>
        </div>

        {/* Analysis Section */}
        <div className="md:col-span-1 space-y-6">
          <div className="bg-suno-card border border-white/10 rounded-xl overflow-hidden shadow-lg h-full">
            <div className="bg-white/5 px-6 py-3 border-b border-white/10 flex items-center gap-2 text-blue-400">
              <Info className="w-4 h-4" />
              <h3 className="font-mono text-sm font-bold uppercase tracking-widest">Architect Analysis</h3>
            </div>
            <div className="p-6">
              <p className="text-white/70 text-sm leading-relaxed">
                {data.analysis}
              </p>
            </div>
          </div>

          <div className="bg-gradient-to-br from-suno-primary/20 to-suno-secondary/20 border border-white/5 rounded-xl p-6">
            <h4 className="text-white font-bold mb-2 text-sm">Pro Tip</h4>
            <p className="text-xs text-white/60">
              Paste the "Style Prompt" into the Style field in Suno Custom Mode. Paste the lyrics into the Lyrics field. If the song cuts off, use the "Extend" feature from the Outro.
            </p>
          </div>
        </div>

      </div>
    </div>
  );
};

export default ResultDisplay;

import React, { useState } from 'react';
import Header from './components/Header';
import BlueprintForm from './components/BlueprintForm';
import ResultDisplay from './components/ResultDisplay';
import { generateBlueprint } from './services/geminiService';
import { UserInput, SunoBlueprintResponse, LoadingState } from './types';
import { AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [loadingState, setLoadingState] = useState<LoadingState>(LoadingState.IDLE);
  const [result, setResult] = useState<SunoBlueprintResponse | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFormSubmit = async (input: UserInput) => {
    setLoadingState(LoadingState.LOADING);
    setError(null);
    setResult(null);

    try {
      const data = await generateBlueprint(input);
      setResult(data);
      setLoadingState(LoadingState.SUCCESS);
    } catch (err: any) {
      setError(err.message || "Something went wrong while generating the blueprint.");
      setLoadingState(LoadingState.ERROR);
    }
  };

  return (
    <div className="min-h-screen bg-[#09090b] text-white flex flex-col font-sans selection:bg-suno-primary selection:text-white pb-20">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-8 space-y-12">
        <section className="flex flex-col items-center justify-center space-y-6">
          <div className="text-center max-w-xl space-y-2">
            <h2 className="text-2xl font-bold text-white">Design Your Sound</h2>
            <p className="text-white/50">
              Input your concept below. The AI Architect will engineer the optimal Suno prompts and lyrical structure for professional-grade generation.
            </p>
          </div>

          <BlueprintForm 
            onSubmit={handleFormSubmit} 
            loadingState={loadingState}
          />
        </section>

        {loadingState === LoadingState.ERROR && (
          <div className="max-w-2xl mx-auto bg-red-500/10 border border-red-500/50 text-red-200 px-6 py-4 rounded-xl flex items-center gap-3 animate-in fade-in slide-in-from-top-2">
            <AlertCircle className="w-5 h-5 flex-shrink-0" />
            <p>{error}</p>
          </div>
        )}

        {result && (
          <section className="border-t border-white/5 pt-12">
             <div className="flex items-center justify-center mb-8">
              <span className="bg-[#09090b] px-4 text-sm font-mono text-white/40 uppercase tracking-widest">
                Blueprint Generated
              </span>
             </div>
            <ResultDisplay data={result} />
          </section>
        )}
      </main>

      <footer className="text-center py-8 text-white/20 text-xs">
        <p>Use generated outputs with Suno AI Custom Mode.</p>
        <p className="mt-1">© {new Date().getFullYear()} Suno AI Architect</p>
      </footer>
    </div>
  );
};

export default App;

