            >
              <option value="">
                {fileName ? "✨ Auto-detect from Audio Reference" : "✨ Auto / AI Decision"}
              </option>
              {STRUCTURE_OPTIONS.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
