import { GoogleGenAI, Type } from "@google/genai";
import { UserInput, SunoBlueprintResponse } from "../types";

const SYSTEM_INSTRUCTION = `
## ROLE
Anda adalah "Suno AI Master Architect", asisten ahli dalam merancang blueprint musik (Style & Lyrics) untuk Suno AI. 

## CAPABILITIES
Anda dapat menerima input teks DAN/ATAU input audio (file mp3/wav).
- Jika user memberikan audio: Anda harus MENDENGARKAN dan MENGANALISIS karakteristik sonik (Genre, Mood, Tempo, Instrumen, Gaya Vokal) dari audio tersebut. Jadikan analisis audio sebagai basis utama "suno_style".
- Jika user memberikan input teks (Genre, Mood, dll) bersamaan dengan audio: Gunakan input teks untuk menyempurnakan atau mengarahkan tema lirik, tetapi biarkan "Vibe/Style" musik mengikuti audio referensi kecuali diminta sebaliknya.

## WORKFLOW LOGIC
1. Analisis Input (Audio, Teks, & Advanced Toggles).
2. Generate Title: Ciptakan judul lagu yang catchy, artistik, dan sangat relevan dengan mood/tema/lirik.
3. Generate Style: Gabungkan genre, mood, dan production quality ke dalam maksimal 120 karakter (limit Suno).
4. Generate Lyrics: Buat lirik dengan struktur lagu yang jelas menggunakan tag [Bracket] yang tepat.

## STYLE OPTIMIZATION RULES
- Gunakan deskripsi tekstur suara (misal: "Warm Analog", "Crispy Highs").
- Gunakan instrumen spesifik (misal: "Suling Javanese flute", "Heavy Reverb Synth").
- Hindari kata-kata deskriptif yang tidak berguna (misal: "Amazing", "Best").
- Pastikan Bahasa yang dipilih tercermin dalam diksi lirik.
- STRICT LIMIT: The 'suno_style' must be under 120 characters.

## LYRICS STRUCTURE RULES
- Follow the 'Structure Blueprint' provided by the user EXACTLY.
- If 'Auto' is selected and Audio Reference is present: ANALYZE the song structure of the audio file (e.g., if the audio starts with a chorus, start the lyrics with a chorus). Mirror the audio's flow.
- [Intro]
- [Verse 1]
- [Chorus]
- [Drop] (Jika EDM) or [Instrumental Interlude]
- [Bridge]
- [Outro]

## ADVANCED FEATURES (Handle Appropriately)
- If EARWORM MODE is active: Create shorter, punchier lines. Make the Chorus simpler and extremely repetitive. Use rhymes that are easy to remember.
- If HUMANIZE VOCALS is active: You MUST insert non-musical vocal tags inside the lyrics like [breath], [sigh], [chuckle], [clears throat], [whisper], or [shout]. Place them for dramatic effect.
- If MELODY GUIDE is active: Include parenthetical guidelines inside the lyrics line to describe how it should be sung. Examples: (upbeat), (slows down), (rising pitch), (spoken).

## FORMAT OUTPUT
You must return a JSON object.
`;

export const generateBlueprint = async (input: UserInput): Promise<SunoBlueprintResponse> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Construct the prompt content
  const contents: any[] = [];

  // 1. Add Audio Part if it exists
  if (input.audioData) {
    contents.push({
      inlineData: {
        mimeType: input.audioMimeType || 'audio/mp3',
        data: input.audioData
      }
    });
  }

  // 2. Add Text Prompt Part
  let promptText = `Create a Suno AI blueprint (Title, Style, Lyrics) for the following song concept.`;

  if (input.audioData) {
    promptText += `
    IMPORTANT: An audio reference file has been provided. 
    1. ANALYZE the audio to determine the Genre, Mood, Tempo, and Vocal Style. 
    2. USE these characteristics to construct the 'suno_style'.
    3. Use the following user preferences to guide the lyrical theme and specific nuances, but prioritize the audio's sonic vibe for the style prompt.
    `;
  }

  promptText += `
    User Preferences:
    - Genre/Style Input: ${input.genre || "Analyze from audio"}
    - Mood/Vibe Input: ${input.mood || "Analyze from audio"}

    - Vocals Input: ${input.vocals.includes('Auto') ? "ANALYZE FROM AUDIO (Identify if Male/Female/Duet/etc)" : input.vocals}
    - Tempo Input: ${input.tempo.includes('Auto') ? "ANALYZE FROM AUDIO (Identify BPM range)" : input.tempo}
    - Language: ${input.language.includes('Auto') ? "ANALYZE FROM AUDIO (Identify language or default to English)" : input.language}

    - Specific Instruments (MUST BE INCLUDED IN STYLE): ${input.instruments && input.instruments.length > 0 ? input.instruments.join(', ') : "None selected"}

    - Additional Details: ${input.additionalDetails}

    PRODUCTION TEXTURE PREFERENCE: ${input.productionTexture} (Ensure this sonic characteristic is explicitly included in the 'suno_style' to define the audio quality).

    STRUCTURE BLUEPRINT: ${input.structure ? input.structure : "AUTO-DETECT (If audio is present, analyze and mimic its structure. If not, choose best fit for genre)."}

    ADVANCED SETTINGS:
    - EARWORM MODE: ${input.isEarworm ? "ENABLED (Make it extremely catchy and repetitive)" : "Disabled"}
    - HUMANIZE VOCALS: ${input.isHumanize ? "ENABLED (Inject breaths, laughs, etc)" : "Disabled"}
    - MELODY GUIDE: ${input.isMelodyGuide ? "ENABLED (Add instructional tags)" : "Disabled"}
  `;

  contents.push({ text: promptText });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', // Supports audio/multimodal
      contents: input.audioData ? { parts: contents } : contents[contents.length - 1].text, 
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suno_title: {
              type: Type.STRING,
              description: "A creative, catchy, and relevant title for the song.",
            },
            suno_style: {
              type: Type.STRING,
              description: "The optimized style prompt for Suno (max 120 chars). Derived from audio reference if provided. Include the production texture tags and the specific instruments requested.",
            },
            suno_lyrics: {
              type: Type.STRING,
              description: "The complete lyrics with bracketed structural tags. IMPORTANT: Structure MUST follow the provided 'Structure Blueprint'. Include [breath] tags if Humanize is on.",
            },
            analysis: {
              type: Type.STRING,
              description: "Brief explanation of why this combination was chosen, noting the structure and advanced features applied.",
            },
          },
          required: ["suno_title", "suno_style", "suno_lyrics", "analysis"],
        },
      },
    });

    if (response.text) {
      return JSON.parse(response.text) as SunoBlueprintResponse;
    }
    throw new Error("No response generated");
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { UserInput, LoadingState, Preset } from '../types';
import { VOCAL_TYPES, TEMPO_OPTIONS, GENRE_EXAMPLES, PRODUCTION_TEXTURES, STRUCTURE_OPTIONS } from '../constants';
import { Sparkles, Loader2, UploadCloud, Music, X, Star, User, TrendingUp, AudioLines, Layers, Save, Bookmark, Trash2, Check, Guitar } from 'lucide-react';

interface BlueprintFormProps {
  onSubmit: (data: UserInput) => void;
  loadingState: LoadingState;
}

const BlueprintForm: React.FC<BlueprintFormProps> = ({ onSubmit, loadingState }) => {
  const [formData, setFormData] = useState<UserInput>({
    genre: '',
    mood: '',
    vocals: 'Male Vocal',
    language: 'English',
    tempo: 'Mid-Tempo (90-110 BPM)',
    instruments: [], // Initialize instruments array
    additionalDetails: '',
    productionTexture: 'Warm Analog (Anti-Metallic)',
    structure: '', // Default to empty (Auto)
    isEarworm: false,
    isHumanize: true, 
    isMelodyGuide: false
  });

  // Audio State
  const [fileName, setFileName] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Instrument Input State
  const [instrumentInput, setInstrumentInput] = useState('');

  // Preset State
  const [presets, setPresets] = useState<Preset[]>([]);
  const [isSavingPreset, setIsSavingPreset] = useState(false);
  const [newPresetName, setNewPresetName] = useState('');
  const [selectedPresetId, setSelectedPresetId] = useState<string>("");

  // Load presets from localStorage on mount
  useEffect(() => {
    const savedPresets = localStorage.getItem('suno_architect_presets');
    if (savedPresets) {
      try {
        setPresets(JSON.parse(savedPresets));
      } catch (e) {
        console.error("Failed to parse presets", e);
      }
    }
  }, []);

  const handleSavePreset = () => {
    if (!newPresetName.trim()) return;

    // Create preset object (excluding large audio data)
    const { audioData, audioMimeType, ...dataToSave } = formData;

    const newPreset: Preset = {
      id: Date.now().toString(),
      name: newPresetName.trim(),
      data: dataToSave
    };

    const updatedPresets = [...presets, newPreset];
    setPresets(updatedPresets);
    localStorage.setItem('suno_architect_presets', JSON.stringify(updatedPresets));

    setIsSavingPreset(false);
    setNewPresetName('');
    setSelectedPresetId(newPreset.id);
  };

  const handleLoadPreset = (id: string) => {
    setSelectedPresetId(id);
    if (!id) return;

    const preset = presets.find(p => p.id === id);
    if (preset) {
      // Preserve current audio data if exists, overwrite other fields
      setFormData(prev => ({
        ...prev,
        ...preset.data,
        instruments: preset.data.instruments || [], // Fallback for legacy presets
        audioData: prev.audioData, // Keep existing audio
        audioMimeType: prev.audioMimeType // Keep existing audio
      }));
    }
  };

  const handleDeletePreset = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const updatedPresets = presets.filter(p => p.id !== id);
    setPresets(updatedPresets);
    localStorage.setItem('suno_architect_presets', JSON.stringify(updatedPresets));
    if (selectedPresetId === id) setSelectedPresetId("");
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleToggle = (name: keyof UserInput) => {
    setFormData(prev => ({ ...prev, [name]: !prev[name] }));
  };

  // Instrument Tag Logic
  const handleInstrumentKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault();
      const val = instrumentInput.trim();
      if (val && !formData.instruments.includes(val)) {
        setFormData(prev => ({ ...prev, instruments: [...prev.instruments, val] }));
        setInstrumentInput('');
      }
    } else if (e.key === 'Backspace' && !instrumentInput && formData.instruments.length > 0) {
      // Remove last tag on backspace if input is empty
      setFormData(prev => ({ ...prev, instruments: prev.instruments.slice(0, -1) }));
    }
  };

  const removeInstrument = (tag: string) => {
    setFormData(prev => ({ ...prev, instruments: prev.instruments.filter(t => t !== tag) }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) { // 10MB limit
        alert("File size too large. Please upload an MP3 under 10MB.");
        return;
      }

      const reader = new FileReader();
      reader.onload = (event) => {
        const base64String = (event.target?.result as string).split(',')[1];
        setFormData(prev => ({
          ...prev,
          audioData: base64String,
          audioMimeType: file.type,
          // Auto-detect triggers
          vocals: '✨ Auto-detect (Match Audio)',
          tempo: '✨ Auto-detect (Match Audio)',
          language: '✨ Auto-detect (Match Audio)'
        }));
        setFileName(file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const clearFile = () => {
    setFormData(prev => ({ 
      ...prev, 
      audioData: undefined, 
      audioMimeType: undefined,
      // Reset to defaults if file is removed
      vocals: 'Male Vocal',
      tempo: 'Mid-Tempo (90-110 BPM)',
      language: 'English'
    }));
    setFileName(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleLanguageFocus = () => {
    if (formData.language.includes('Auto-detect')) {
      setFormData(prev => ({ ...prev, language: '' }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  const isLoading = loadingState === LoadingState.LOADING;

  return (
    <div className="w-full max-w-2xl mx-auto p-6 bg-suno-card border border-white/10 rounded-2xl shadow-xl space-y-6">

      {/* PRESET MANAGER TOOLBAR */}
      <div className="bg-white/5 rounded-xl p-4 border border-white/5 flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex items-center gap-2 text-white/70 w-full md:w-auto">
          <Bookmark className="w-4 h-4 text-suno-primary" />
          <span className="text-sm font-mono uppercase tracking-wider">Presets</span>
        </div>

        {isSavingPreset ? (
          <div className="flex items-center gap-2 w-full md:w-auto animate-in fade-in slide-in-from-right-4 duration-300">
            <input
              type="text"
              placeholder="Preset Name..."
              value={newPresetName}
              onChange={(e) => setNewPresetName(e.target.value)}
              className="bg-black/40 border border-white/20 rounded-lg px-3 py-1.5 text-sm text-white focus:outline-none focus:border-suno-primary w-full md:w-48"
              autoFocus
            />
            <button 
              onClick={handleSavePreset}
              className="p-1.5 bg-green-500/20 text-green-400 hover:bg-green-500/30 rounded-lg transition-colors"
            >
              <Check className="w-4 h-4" />
            </button>
            <button 
              onClick={() => setIsSavingPreset(false)}
              className="p-1.5 bg-red-500/20 text-red-400 hover:bg-red-500/30 rounded-lg transition-colors"
            >
              <X className="w-4 h-4" />
            </button>
          </div>
        ) : (
          <div className="flex items-center gap-3 w-full md:w-auto">
            <div className="relative flex-grow md:flex-grow-0 min-w-[200px]">
              <select
                value={selectedPresetId}
                onChange={(e) => handleLoadPreset(e.target.value)}
                className="w-full bg-black/40 border border-white/10 rounded-lg pl-3 pr-8 py-2 text-sm text-white focus:outline-none focus:border-white/30 appearance-none cursor-pointer hover:bg-white/5 transition-colors"
              >
                <option value="">Load a preset...</option>
                {presets.map(p => (
                  <option key={p.id} value={p.id}>{p.name}</option>
                ))}
              </select>
              {selectedPresetId && (
                 <button
                 onClick={(e) => handleDeletePreset(e, selectedPresetId)}
                 className="absolute right-8 top-1/2 -translate-y-1/2 p-1 text-white/30 hover:text-red-400 transition-colors"
                 title="Delete Preset"
               >
                 <Trash2 className="w-3 h-3" />
               </button>
              )}
              <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none">
                <svg className="w-3 h-3 text-white/50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
              </div>
            </div>

            <button
              onClick={() => setIsSavingPreset(true)}
              className="flex items-center gap-2 px-3 py-2 bg-suno-primary/20 hover:bg-suno-primary/30 text-suno-primary border border-suno-primary/30 rounded-lg text-sm transition-all"
            >
              <Save className="w-4 h-4" />
              <span className="hidden sm:inline">Save</span>
            </button>
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Audio Reference Upload */}
        <div className="space-y-2">
          <label className="text-xs font-mono uppercase tracking-wider text-white/50">
            Audio Reference (Optional)
          </label>
          <div className="relative group">
            {!fileName ? (
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="w-full border-2 border-dashed border-white/10 rounded-xl p-6 flex flex-col items-center justify-center gap-2 cursor-pointer hover:border-suno-primary/50 hover:bg-white/5 transition-all"
              >
                <UploadCloud className="w-8 h-8 text-suno-primary/70" />
                <p className="text-sm text-white/60">Click to upload MP3 reference</p>
                <p className="text-xs text-white/30">AI will auto-detect Genre, Vocals & Tempo</p>
              </div>
            ) : (
              <div className="w-full bg-suno-primary/10 border border-suno-primary/30 rounded-xl p-4 flex items-center justify-between">
                <div className="flex items-center gap-3 overflow-hidden">
                  <div className="w-10 h-10 rounded-lg bg-suno-primary/20 flex items-center justify-center flex-shrink-0">
                    <Music className="w-5 h-5 text-suno-primary" />
